"""Stats filtering, transformation, and pattern ID assignment.

Functions that operate on the stats dictionary (named_ops / generic_ops)
used throughout the pipeline.
"""

import copy
from pathlib import Path

from ..formatting import compact_json_dumps


def filter_stats_by_op(stats, op_filter):
    """Filter stats dictionary to include only the specified operator type.

    Args:
        stats: Full statistics dictionary with named_ops, generic_ops, and fused_ops
        op_filter: Operator filter - None (all), "generic", or named op like "matmul"

    Returns:
        Filtered stats dictionary
    """
    if op_filter is None:
        return stats

    filtered = {}

    if op_filter == "generic":
        filtered["generic_ops"] = stats.get("generic_ops", {})
        filtered["named_ops"] = {}
        filtered["fused_ops"] = {}
    else:
        target_op = f"linalg.{op_filter}"
        filtered["generic_ops"] = {}
        filtered["named_ops"] = {}
        if "named_ops" in stats and target_op in stats["named_ops"]:
            filtered["named_ops"][target_op] = stats["named_ops"][target_op]

        # Include fused_ops where primary_op matches
        filtered["fused_ops"] = {}
        for fp_hash, fused_data in stats.get("fused_ops", {}).items():
            if fused_data.get("primary_op") == target_op:
                filtered["fused_ops"][fp_hash] = fused_data

    return filtered


def _filter_section_by_type(section, type_filter):
    """Filter one ops section (named_ops or generic_ops) by operand dtype.

    Removes patterns whose inputs don't all match type_filter.
    Removes operators that have no remaining patterns.

    Args:
        section: Dict mapping op names to op data (with shape_patterns)
        type_filter: Operand type to keep (e.g., "f32", "i8")

    Returns:
        Filtered section dict
    """
    result = {}
    for op_name, op_data in section.items():
        matching_patterns = []
        total_count = 0

        for pattern in op_data.get("shape_patterns", []):
            inputs = pattern.get("inputs", [])
            if all(inp.get("dtype") == type_filter for inp in inputs):
                matching_patterns.append(pattern)
                total_count += pattern.get("count", 0)

        if matching_patterns:
            result[op_name] = dict(op_data)
            result[op_name]["shape_patterns"] = matching_patterns
            result[op_name]["total_count"] = total_count

    return result


def filter_stats_by_type(stats, type_filter):
    """Filter stats dictionary to include only patterns with the specified operand type.

    Args:
        stats: Full statistics dictionary with named_ops and generic_ops
        type_filter: Operand type filter - None (all), "f32", or "i8"

    Returns:
        Filtered stats dictionary
    """
    if type_filter is None:
        return stats

    filtered = copy.deepcopy(stats)
    filtered["named_ops"] = _filter_section_by_type(
        filtered.get("named_ops", {}), type_filter
    )
    filtered["generic_ops"] = _filter_section_by_type(
        filtered.get("generic_ops", {}), type_filter
    )
    filtered["fused_ops"] = _filter_section_by_type(
        filtered.get("fused_ops", {}), type_filter
    )
    return filtered


def _count_search_space_configs(filepath):
    """Count non-empty, non-comment lines in search space file."""
    if not filepath:
        return None
    try:
        with open(filepath, 'r') as f:
            count = sum(1 for line in f
                        if line.strip() and not line.strip().startswith('#'))
        return count
    except (FileNotFoundError, IOError):
        return 0


def _assign_ids_to_section(section):
    """Assign pattern IDs and clean up fields for one ops section.

    For each shape_pattern:
    - Adds 'op_pattern_id' with sequential index as string
    - Renames 'lowering_config' to 'default_tile_config'
    - Removes 'autoiree_tile_configs'
    - Adds 'num_tile_configs' from search_space_filepath

    Args:
        section: Dict mapping op names to op data
    """
    for op_name, op_data in section.items():
        for idx, pattern in enumerate(op_data.get("shape_patterns", [])):
            pattern["op_pattern_id"] = str(idx)
            if "lowering_config" in pattern:
                pattern["default_tile_config"] = pattern.pop("lowering_config")
            if "autoiree_tile_configs" in pattern:
                del pattern["autoiree_tile_configs"]
            search_space_filepath = pattern.get("search_space_filepath")
            if search_space_filepath:
                num_configs = _count_search_space_configs(search_space_filepath)
                pattern["num_tile_configs"] = num_configs


def assign_pattern_ids(stats):
    """Assign unique IDs to each pattern and clean up fields.

    For each shape_pattern in stats:
    - Adds 'op_pattern_id' field with sequential index as string (e.g., "0", "1")
    - Renames 'lowering_config' to 'default_tile_config'
    - Removes 'autoiree_tile_configs' field
    - Adds 'num_tile_configs' field with count of configs in search_space_filepath (if exists)

    Args:
        stats: Statistics dictionary with named_ops and generic_ops

    Returns:
        Modified stats dictionary with IDs assigned
    """
    result = copy.deepcopy(stats)
    _assign_ids_to_section(result.get("named_ops", {}))
    _assign_ids_to_section(result.get("generic_ops", {}))
    _assign_ids_to_section(result.get("fused_ops", {}))
    return result


def save_patterns_json(stats, pattern_file, op_filter=None, type_filter=None):
    """Save patterns.json with assigned IDs and search_space_filepath fields.

    Applies optional filters, assigns pattern IDs, and writes to file.

    Args:
        stats: Statistics dictionary with named_ops and generic_ops
        pattern_file: Path to write patterns.json
        op_filter: Optional operator name filter
        type_filter: Optional dtype filter
    """
    filtered = filter_stats_by_op(stats, op_filter)
    filtered = filter_stats_by_type(filtered, type_filter)
    filtered = assign_pattern_ids(filtered)
    with open(pattern_file, 'w') as f:
        f.write(compact_json_dumps(filtered, indent=2))
    return filtered


def build_stats_for_pattern_id(patterns_data, op_filter, pattern_id):
    """Build stats dict containing only the pattern with the given op_pattern_id.

    Scans named_ops then generic_ops for a pattern matching the ID.
    When op_filter is "generic", searches only generic_ops.
    Otherwise, searches the specific named op (linalg.{op_filter}).

    Preserves iterator_types, template from the parent op.

    Args:
        patterns_data: Loaded patterns.json dict
        op_filter: Short op name (e.g., 'matmul', 'generic')
        pattern_id: op_pattern_id string to find (e.g., "0", "5")

    Returns:
        Stats dict with named_ops and generic_ops, containing only the matched pattern.

    Raises:
        ValueError: If pattern not found.
    """
    if op_filter == "generic":
        search_sections = [("generic_ops", patterns_data.get("generic_ops", {}))]
    else:
        target_op = f"linalg.{op_filter}"
        search_sections = []
        named_ops = patterns_data.get("named_ops", {})
        if target_op in named_ops:
            search_sections.append(("named_ops", {target_op: named_ops[target_op]}))
        # Also search fused_ops with matching primary_op
        fused_ops = patterns_data.get("fused_ops", {})
        fused_matching = {k: v for k, v in fused_ops.items()
                         if v.get("primary_op") == target_op}
        if fused_matching:
            search_sections.append(("fused_ops", fused_matching))

    for section_key, ops in search_sections:
        for op_name, op_data in ops.items():
            for pattern in op_data.get("shape_patterns", []):
                if pattern.get("op_pattern_id") == str(pattern_id):
                    op_entry = {
                        "iterator_types": op_data.get("iterator_types", []),
                        "total_count": 1,
                        "shape_patterns": [pattern],
                    }
                    if "template" in op_data:
                        op_entry["template"] = op_data["template"]
                    if "extra_inputs_spec" in op_data:
                        op_entry["extra_inputs_spec"] = op_data["extra_inputs_spec"]
                    if "fingerprint" in op_data:
                        op_entry["fingerprint"] = op_data["fingerprint"]
                    if "primary_op" in op_data:
                        op_entry["primary_op"] = op_data["primary_op"]

                    if section_key == "named_ops":
                        return {
                            "named_ops": {op_name: op_entry},
                            "generic_ops": {},
                        }
                    elif section_key == "fused_ops":
                        return {
                            "named_ops": {},
                            "generic_ops": {},
                            "fused_ops": {op_name: op_entry},
                        }
                    else:
                        return {
                            "named_ops": {},
                            "generic_ops": {op_name: op_entry},
                        }

    raise ValueError(
        f"Pattern ID '{pattern_id}' not found in patterns data "
        f"(op_filter={op_filter!r})"
    )
